import React, { useState } from 'react';
import api from '../api/client';

const EconomicPage = () => {
  const [form, setForm] = useState({
    company_name: '',
    number_of_employees: '',
    monthly_sales: '',
    expected_growth: '',
    license_cost_per_user: ''
  });
  const [result, setResult] = useState(null);
  const [error, setError] = useState('');

  const submit = async (event) => {
    event.preventDefault();
    setError('');
    const payload = {
      ...form,
      number_of_employees: Number(form.number_of_employees),
      monthly_sales: Number(form.monthly_sales),
      expected_growth: Number(form.expected_growth),
      license_cost_per_user: Number(form.license_cost_per_user)
    };

    try {
      const { data } = await api.post('/economic', payload);
      setResult(data);
    } catch (requestError) {
      setError('Ошибка расчёта. Проверьте введённые данные.');
    }
  };

  return (
    <section>
      <h2>Экономическое обоснование</h2>
      <form className="form" onSubmit={submit}>
        <input
          placeholder="Название компании"
          value={form.company_name}
          onChange={(e) => setForm({ ...form, company_name: e.target.value })}
          required
        />
        <input
          type="number"
          min="1"
          placeholder="Количество сотрудников"
          value={form.number_of_employees}
          onChange={(e) => setForm({ ...form, number_of_employees: e.target.value })}
          required
        />
        <input
          type="number"
          min="0"
          placeholder="Сумма продаж в месяц"
          value={form.monthly_sales}
          onChange={(e) => setForm({ ...form, monthly_sales: e.target.value })}
          required
        />
        <input
          type="number"
          min="0"
          step="0.1"
          placeholder="Прогнозируемый рост продаж (%)"
          value={form.expected_growth}
          onChange={(e) => setForm({ ...form, expected_growth: e.target.value })}
          required
        />
        <input
          type="number"
          min="0"
          placeholder="Стоимость лицензии за пользователя"
          value={form.license_cost_per_user}
          onChange={(e) => setForm({ ...form, license_cost_per_user: e.target.value })}
          required
        />
        <button type="submit">Рассчитать</button>
      </form>

      {error && <p className="error">{error}</p>}

      {result && (
        <div className="result-card">
          <p>
            Годовые затраты (TCO): <strong>{Number(result.annual_cost).toFixed(2)} ₽</strong>
          </p>
          <p>
            Прогнозируемая годовая прибыль: <strong>{Number(result.projected_annual_profit).toFixed(2)} ₽</strong>
          </p>
          <p>
            Срок окупаемости (месяцы):{' '}
            <strong>
              {result.payback_months ? Number(result.payback_months).toFixed(2) : 'Невозможно рассчитать'}
            </strong>
          </p>
          <p>
            Сегмент компании: <strong>{result.company_profile.employee_segment}</strong>
          </p>
          <p>
            Сегмент продаж: <strong>{result.company_profile.sales_segment}</strong>
          </p>
          <p>
            Доля затрат CRM от годовой выручки:{' '}
            <strong>{Number(result.company_profile.crm_cost_share_percent).toFixed(2)}%</strong>
          </p>
          <p>Итоговая рекомендация: <strong>{result.recommendation}</strong></p>

          {result.recommendation_details?.length > 0 && (
            <div className="recommendation-list">
              <p><strong>Практические рекомендации:</strong></p>
              {result.recommendation_details.map((item) => (
                <p key={item}>• {item}</p>
              ))}
            </div>
          )}
        </div>
      )}
    </section>
  );
};

export default EconomicPage;
